// ─── HELPERS ────────────────────────────────────────────────────────────────

// Year range for Plan Month picker — extend freely without touching dropdown lists
const PLAN_MONTH_YEARS = [];
for (let y = 2024; y <= 2035; y++) PLAN_MONTH_YEARS.push(y);

function parsePlanMonth(pm) {
  if (!pm) return null;
  const [m, y] = pm.split("-");
  const mi = MONTHS.indexOf(m);
  if (mi === -1) return null;
  const year = parseInt("20" + y);
  return { month: mi, year };
}

function getFY(planMonth) {
  const p = parsePlanMonth(planMonth);
  if (!p) return "";
  const { month, year } = p;
  // Indian FY: Apr–Mar
  // Apr(3)–Sep(8)  → H1 of (year+1)   e.g. Apr-25 = 2026-H1
  // Oct(9)–Dec(11) → H2 of (year+1)   e.g. Oct-25 = 2026-H2
  // Jan(0)–Mar(2)  → H2 of same year  e.g. Mar-26 = 2026-H2
  if (month >= 3 && month <= 8) return `${year + 1}-H1`;
  if (month >= 9)               return `${year + 1}-H2`;
  return `${year}-H2`;
}

function getPnLBreakup(billingFreq) {
  return PNL_BREAKUP[billingFreq] || 12;
}

function calcBudget(rate, qty, currency, rates) {
  const r = rates || DEFAULT_CONVERSION_RATES;
  const total = (parseFloat(rate) || 0) * (parseFloat(qty) || 0);
  const rate2sgd = r[currency] || 1;
  return Math.round(total * rate2sgd * 100) / 100;
}

function calcTotal(rate, qty) {
  return (parseFloat(rate) || 0) * (parseFloat(qty) || 0);
}

// ─── ACTUAL NORMALISATION ─────────────────────────────────────────────────────
// Always store actual as number | null. Never store "" or "0".
function toActual(v) {
  if (v === null || v === undefined || v === "") return null;
  const n = parseFloat(v);
  return Number.isFinite(n) && n > 0 ? Math.round(n * 100) / 100 : null;
}

function fmtActual(v) {
  return v != null ? v.toLocaleString() : "—";
}

// Generate monthly P&L columns: returns object {month_key: value}
function calcPnLMonths(item) {
  const p = parsePlanMonth(item.planMonth);
  if (!p) return {};
  const pnlBreakup = getPnLBreakup(item.billingFreq);
  // actual is now number|null — no parseFloat needed
  const actualVal = (item.actual != null && item.actual > 0) ? item.actual : null;
  const costVal = actualVal !== null ? actualVal : (parseFloat(item.budget) || 0);
  const monthly = costVal / pnlBreakup;
  const result = {};
  for (let i = 0; i < pnlBreakup; i++) {
    let mo = p.month + i;
    let yr = p.year;
    while (mo > 11) { mo -= 12; yr++; }
    const key = `${MONTHS[mo]}-${String(yr).slice(2)}`;
    result[key] = (result[key] || 0) + monthly;
  }
  return result;
}

function getFYHalves() {
  const halves = [];
  for (let y = 2022; y <= 2028; y++) {
    halves.push(`FY${y + 1}-H1`);
    halves.push(`FY${y + 1}-H2`);
  }
  return halves;
}

function getPnLForFYHalf(item, fyHalf) {
  // fyHalf like "FY2026-H1"
  const match = fyHalf.match(/FY(\d+)-(H[12])/);
  if (!match) return 0;
  const fy = parseInt(match[1]);
  const half = match[2];
  // H1 = Apr-Sep of previous year, H2 = Oct-Mar
  const startMonth = half === "H1" ? 3 : 9; // 0-indexed: Apr=3, Oct=9
  const endMonth = half === "H1" ? 8 : 2;
  const startYear = half === "H1" ? fy - 1 : fy - 1;
  const endYear = half === "H1" ? fy - 1 : fy;
  const pnl = calcPnLMonths(item);
  let sum = 0;
  for (const [key, val] of Object.entries(pnl)) {
    const [m, y] = key.split("-");
    const mi = MONTHS.indexOf(m);
    const yr = parseInt("20" + y);
    if (half === "H1") {
      if (yr === startYear && mi >= startMonth && mi <= endMonth) sum += val;
    } else {
      if ((yr === startYear && mi >= startMonth) || (yr === endYear && mi <= endMonth)) sum += val;
    }
  }
  return Math.round(sum * 100) / 100;
}

function getDaysUntil(planMonth) {
  const p = parsePlanMonth(planMonth);
  if (!p) return null;
  const target = new Date(p.year, p.month, 1);
  const today = new Date();
  const diff = Math.ceil((target - today) / (1000 * 60 * 60 * 24));
  return diff;
}

const FY_HALVES = getFYHalves();

